import React, { useState, useEffect } from 'react';
import {
  Box,
  Typography,
  TextField,
  Button,
  Grid,
  Paper,
  Chip,
  Divider,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  IconButton,
  SelectChangeEvent
} from '@mui/material';
import { Add, Delete } from '@mui/icons-material';
import { useFirebase } from '../../context/FirebaseContext';
import { CarSpecifications, Raffle } from '../../types';

interface CarSpecificationsFormProps {
  raffle: Raffle;
  onCancel: () => void;
  onSaved: () => void;
}

const initialSpecsState: CarSpecifications = {
  make: '',
  model: '',
  year: new Date().getFullYear(),
  engine: {
    type: '',
    displacement: '',
    horsepower: 0,
    torque: ''
  },
  transmission: '',
  drivetrain: '',
  acceleration: '',
  topSpeed: '',
  features: [],
  exteriorColor: '',
  interiorColor: '',
  dimensions: {
    length: '',
    width: '',
    height: '',
    wheelbase: ''
  },
  weight: '',
  fuelEconomy: ''
};

const CarSpecificationsForm: React.FC<CarSpecificationsFormProps> = ({ raffle, onCancel, onSaved }) => {
  const { updateCarSpecs } = useFirebase();
  const [specs, setSpecs] = useState<CarSpecifications>(raffle.carSpecifications || initialSpecsState);
  const [newFeature, setNewFeature] = useState('');
  
  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setSpecs(prev => ({
        ...prev,
        [parent]: {
          ...prev[parent as keyof CarSpecifications],
          [child]: value
        }
      }));
    } else {
      setSpecs(prev => ({
        ...prev,
        [name]: value
      }));
    }
  };
  
  const handleNumberChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setSpecs(prev => ({
        ...prev,
        [parent]: {
          ...prev[parent as keyof CarSpecifications],
          [child]: Number(value)
        }
      }));
    } else {
      setSpecs(prev => ({
        ...prev,
        [name]: Number(value)
      }));
    }
  };
  
  const handleAddFeature = () => {
    if (newFeature.trim()) {
      setSpecs(prev => ({
        ...prev,
        features: [...prev.features, newFeature.trim()]
      }));
      setNewFeature('');
    }
  };
  
  const handleDeleteFeature = (index: number) => {
    setSpecs(prev => ({
      ...prev,
      features: prev.features.filter((_, i) => i !== index)
    }));
  };
  
  const handleSave = async () => {
    try {
      await updateCarSpecs(raffle.id, specs);
      onSaved();
    } catch (error) {
      console.error('Ошибка при сохранении спецификаций:', error);
    }
  };
  
  return (
    <Paper sx={{ p: 3, borderRadius: 2, mb: 4 }}>
      <Typography variant="h5" component="h2" gutterBottom>
        Спецификации автомобиля
      </Typography>
      <Divider sx={{ mb: 3 }} />
      
      <Grid container spacing={3}>
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            label="Марка"
            name="make"
            value={specs.make}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            label="Модель"
            name="model"
            value={specs.model}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={4}>
          <TextField
            fullWidth
            label="Год выпуска"
            name="year"
            type="number"
            value={specs.year}
            onChange={handleNumberChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={4}>
          <TextField
            fullWidth
            label="Цвет кузова"
            name="exteriorColor"
            value={specs.exteriorColor}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={4}>
          <TextField
            fullWidth
            label="Цвет салона"
            name="interiorColor"
            value={specs.interiorColor}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        
        <Grid item xs={12}>
          <Typography variant="h6" gutterBottom sx={{ mt: 2 }}>
            Двигатель
          </Typography>
          <Divider sx={{ mb: 2 }} />
        </Grid>
        
        <Grid item xs={12} md={3}>
          <TextField
            fullWidth
            label="Тип двигателя"
            name="engine.type"
            value={specs.engine.type}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={3}>
          <TextField
            fullWidth
            label="Объем (л)"
            name="engine.displacement"
            value={specs.engine.displacement}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={3}>
          <TextField
            fullWidth
            label="Мощность (л.с.)"
            name="engine.horsepower"
            type="number"
            value={specs.engine.horsepower}
            onChange={handleNumberChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={3}>
          <TextField
            fullWidth
            label="Крутящий момент"
            name="engine.torque"
            value={specs.engine.torque}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        
        <Grid item xs={12}>
          <Typography variant="h6" gutterBottom sx={{ mt: 2 }}>
            Трансмиссия и динамика
          </Typography>
          <Divider sx={{ mb: 2 }} />
        </Grid>
        
        <Grid item xs={12} md={4}>
          <TextField
            fullWidth
            label="Коробка передач"
            name="transmission"
            value={specs.transmission}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={3}>
          <TextField
            fullWidth
            label="Привод"
            name="drivetrain"
            value={specs.drivetrain}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={3}>
          <TextField
            fullWidth
            label="Разгон 0-100 км/ч"
            name="acceleration"
            value={specs.acceleration}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={2}>
          <TextField
            fullWidth
            label="Макс. скорость"
            name="topSpeed"
            value={specs.topSpeed}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        
        <Grid item xs={12}>
          <Typography variant="h6" gutterBottom sx={{ mt: 2 }}>
            Размеры и вес
          </Typography>
          <Divider sx={{ mb: 2 }} />
        </Grid>
        
        <Grid item xs={12} md={3}>
          <TextField
            fullWidth
            label="Длина (мм)"
            name="dimensions.length"
            value={specs.dimensions.length}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={3}>
          <TextField
            fullWidth
            label="Ширина (мм)"
            name="dimensions.width"
            value={specs.dimensions.width}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={3}>
          <TextField
            fullWidth
            label="Высота (мм)"
            name="dimensions.height"
            value={specs.dimensions.height}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={3}>
          <TextField
            fullWidth
            label="Колесная база (мм)"
            name="dimensions.wheelbase"
            value={specs.dimensions.wheelbase}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            label="Вес (кг)"
            name="weight"
            value={specs.weight}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            label="Расход топлива"
            name="fuelEconomy"
            value={specs.fuelEconomy}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        
        <Grid item xs={12}>
          <Typography variant="h6" gutterBottom sx={{ mt: 2 }}>
            Комплектация и особенности
          </Typography>
          <Divider sx={{ mb: 2 }} />
        </Grid>
        
        <Grid item xs={12}>
          <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
            <TextField
              fullWidth
              label="Добавить особенность"
              value={newFeature}
              onChange={(e) => setNewFeature(e.target.value)}
              variant="outlined"
              onKeyPress={(e) => e.key === 'Enter' && handleAddFeature()}
            />
            <IconButton 
              color="primary" 
              onClick={handleAddFeature}
              sx={{ ml: 1 }}
            >
              <Add />
            </IconButton>
          </Box>
          
          <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
            {specs.features.map((feature, index) => (
              <Chip
                key={index}
                label={feature}
                onDelete={() => handleDeleteFeature(index)}
                color="primary"
                variant="outlined"
              />
            ))}
          </Box>
        </Grid>
        
        <Grid item xs={12}>
          <Box sx={{ display: 'flex', justifyContent: 'flex-end', mt: 3 }}>
            <Button 
              variant="outlined" 
              onClick={onCancel}
              sx={{ mr: 2 }}
            >
              Отмена
            </Button>
            <Button 
              variant="contained"
              color="primary"
              onClick={handleSave}
            >
              Сохранить
            </Button>
          </Box>
        </Grid>
      </Grid>
    </Paper>
  );
};

export default CarSpecificationsForm;
